// 1. Əsas tiplər
let name: string = "Shirt"; // Sətir
let price: number = 50; // Rəqəm
let inStock: boolean = true; // Doğru/yanlış

// 2. Array və Tuple
let sizes: string[] = ["S", "M", "L"]; // Array
let itemInfo: [string, number] = ["Jacket", 100]; // Tuple

// 3. Enum
enum Category {
  Casual = "Casual",
  Formal = "Formal"
}
const itemCategory: Category = Category.Casual;

// 4. Any və Void
let flexible: any = 42; // Hər hansı tip
flexible = "Hat"; // Səhv olmur
function logMessage(): void {
  console.log("Mesaj yazılır");
}

// 5. Null və Undefined
let empty: null = null;
let notSet: undefined = undefined;

// 6. fetch ilə tip təyinli sorğu
interface Item {
  name: string;
  price: number;
}

async function fetchItem(): Promise<Item | null> {
  try {
    const response = await fetch("https://api.example.com/item");
    if (!response.ok) throw new Error("Şəbəkə xətası");
    const data: Item = await response.json();
    return data;
  } catch (error) {
    console.error("Xəta:", error);
    return null;
  }
}

// 7. DOM manipulyasiyası
const output = document.getElementById("output") as HTMLElement;
const loadBtn = document.getElementById("loadBtn") as HTMLButtonElement;

loadBtn.addEventListener("click", async () => {
  output.textContent = "Yüklənir...";
  const item = await fetchItem();
  output.textContent = item ? `${item.name}: $${item.price}` : "Məhsul tapılmadı";
});

